from flask import Flask, request, redirect, url_for, render_template_string
import os
import secrets
import smtplib
from email.mime.text import MIMEText

app = Flask(__name__)
app.secret_key = os.urandom(24)

# Dummy database for demonstration purposes
users_db = {
    'user1': {'email': 'user1@example.com', 'mfa_enabled': False, 'reset_token': None}
}

def send_email(to_email, subject, body):
    msg = MIMEText(body)
    msg['Subject'] = subject
    msg['From'] = 'your-email@example.com'
    msg['To'] = to_email

    with smtplib.SMTP('smtp.example.com', 587) as server:
        server.starttls()
        server.login('your-email@example.com', 'your-password')
        server.sendmail('your-email@example.com', to_email, msg.as_string())

@app.route('/enable-mfa', methods=['POST'])
def enable_mfa():
    email = request.form['email']
    if email in users_db:
        token = secrets.token_urlsafe()
        users_db[email]['reset_token'] = token
        reset_link = url_for('reset_mfa', token=token, _external=True)
        send_email(email, 'Enable MFA', f'Click this link to enable MFA: {reset_link}')
        return 'MFA enable request sent. Check your email.'
    return 'User not found.', 404

@app.route('/reset-mfa/<token>', methods=['GET'])
def reset_mfa(token):
    if token in users_db:
        users_db[token]['mfa_enabled'] = False
        users_db[token]['reset_token'] = None
        return 'MFA disabled. You can now log in with just your password.'
    return 'Invalid token.', 400

if __name__ == '__main__':
    app.run(debug=True)